#!/usr/bin/env node
/**
 * seed-iconic-walks.mjs — seed ~45 iconic Australian multi-day / adventure walks
 * into autravel.trails tagged state_code='auex' for The Australian Explorer.
 * Rich guide copy generated by scripts/enrich-au-walks.mjs. Idempotent on slug.
 *
 *   node --env-file=.env.local scripts/seed-iconic-walks.mjs
 */
import 'dotenv/config'
import postgres from 'postgres'

const CONN = process.env.DATABASE_URL || ''
const isLocal = /@(127\.0\.0\.1|localhost)[:\/]/.test(CONN)
const sql = postgres(CONN, { ssl: isLocal ? false : 'require', prepare: false, max: 4 })
const STATE = 'auex'

function slugify(s){return String(s).toLowerCase().normalize('NFKD').replace(/[̀-ͯ]/g,'').replace(/[^a-z0-9]+/g,'-').replace(/^-+|-+$/g,'').slice(0,70)}
const km = n => n >= 1 ? `${n} km` : `${Math.round(n*1000)} m`

// [name, area, states, difficulty, length_km, duration, lat, lng, blurb]
const W = [
  ['Overland Track','Cradle Mountain–Lake St Clair, TAS',['tas'],'Challenging',65,'6 days',-41.84,145.95,'Tasmania\'s premier alpine walk from Cradle Mountain to Lake St Clair through buttongrass moors, rainforest and dolerite peaks. Booked, fee-based and one-way north–south in season.'],
  ['Larapinta Trail','West MacDonnell Ranges, NT',['nt'],'Challenging',223,'12-16 days',-23.7,133.2,'A 12-section desert-ranges traverse west of Alice Springs along the Tjoritja/West MacDonnells — quartzite ridgelines, gorges and waterholes, walked end-to-end in the cooler months.'],
  ['Cape to Cape Track','Margaret River, WA',['wa'],'Moderate',123,'5-7 days',-33.97,114.99,'The South-West coast between Cape Naturaliste and Cape Leeuwin — limestone cliffs, karri forest, surf beaches and lighthouses on a well-marked coastal track.'],
  ['Three Capes Track','Tasman Peninsula, TAS',['tas'],'Moderate',48,'4 days',-43.16,147.85,'A guided-standard coastal walk past Australia\'s tallest sea cliffs to Cape Pillar and Cape Hauy, with architect-designed huts. Booked and fee-based.'],
  ['Australian Alps Walking Track','Alps, VIC/NSW/ACT',['vic','nsw'],'Challenging',650,'5-8 weeks',-36.9,147.9,'The continent\'s great alpine traverse from Walhalla to Tharwa across Victoria\'s high country and Kosciuszko — remote, exposed and snow-prone, for experienced walkers.'],
  ['Heysen Trail','Flinders Ranges to Cape Jervis, SA',['sa'],'Challenging',1200,'~8 weeks',-32.0,138.6,'South Australia\'s end-to-end trail from Parachilna Gorge to Cape Jervis through the Flinders, Barossa and Adelaide Hills — closed in the fire-danger summer months.'],
  ['Jatbula Trail','Nitmiluk (Katherine Gorge), NT',['nt'],'Moderate',62,'5-6 days',-14.3,132.4,'A one-way walk along the Arnhem Land escarpment from Nitmiluk to Leliyn (Edith Falls) past waterfalls, rock art and monsoon forest. Dry-season only and booked.'],
  ['Carnarvon Gorge','Central Highlands, QLD',['qld'],'Moderate',87,'1-5 days',-25.05,148.22,'A sandstone gorge network of side-canyons, Aboriginal rock art and cool rainforest pockets — day walks or a multi-day base-camp through one of inland Queensland\'s gems.'],
  ['Grampians Peaks Trail','Grampians (Gariwerd), VIC',['vic'],'Challenging',160,'13 days',-37.15,142.5,'An end-to-end traverse of the Grampians ranges from Mt Zero to Dunkeld linking the best peaks, with hike-in camps. Rugged sandstone, ladders and big views.'],
  ['Wilsons Promontory Southern Circuit','Wilsons Prom, VIC',['vic'],'Moderate',60,'3-4 days',-39.03,146.32,'A classic loop of the southernmost mainland tip — Sealers Cove, Refuge Cove, the lighthouse and Oberon Bay, through forest, granite and white-sand beaches.'],
  ['K\'gari Great Walk','K\'gari (Fraser Island), QLD',['qld'],'Moderate',90,'6-8 days',-25.3,153.1,'The world\'s largest sand island on foot — perched lakes, towering rainforest on sand, and the long ocean beach. Soft tracks, dingoes and remote camps.'],
  ['South Coast Track','Southwest NP, TAS',['tas'],'Challenging',85,'6-8 days',-43.5,146.2,'A remote and committing wilderness walk between Melaleuca (fly-in) and Cockle Creek across the buttongrass and mud of Tasmania\'s wild south coast.'],
  ['Freycinet Peninsula Circuit','Freycinet, TAS',['tas'],'Moderate',30,'2-3 days',-42.16,148.3,'A loop over the pink-granite Hazards to Wineglass Bay, Hazards Beach and Cooks Beach — one of Tasmania\'s most photographed coastlines.'],
  ['Frenchmans Cap','Franklin-Gordon, TAS',['tas'],'Challenging',46,'3-5 days',-42.25,145.8,'A quartzite dome rising above the Franklin wilderness — rebuilt track, dramatic ridgelines and notoriously changeable weather. Hut-based.'],
  ['Walls of Jerusalem','Central Plateau, TAS',['tas'],'Challenging',35,'2-3 days',-41.78,146.27,'A roadless alpine basin of dolomite peaks, tarns and pencil pines — a steep climb in, then quiet camping among the "walls". Carry a tent and warm gear.'],
  ['Great Ocean Walk','Apollo Bay to the Twelve Apostles, VIC',['vic'],'Moderate',104,'8 days',-38.7,143.4,'A one-way coastal walk along the Shipwreck Coast — forest, cliff tops, remote beaches and the Apostles. Walked east–west with the prevailing weather behind you.'],
  ['Six Foot Track','Blue Mountains, NSW',['nsw'],'Moderate',45,'3 days',-33.73,150.3,'Katoomba to the Jenolan Caves on a historic bridle track — the Megalong Valley, the Coxs River and a steep finish. A popular weekend three-dayer.'],
  ['Great North Walk','Sydney to Newcastle, NSW',['nsw'],'Challenging',250,'10-14 days',-33.4,151.3,'A long-distance route linking Sydney Harbour to Newcastle through national parks, ridgelines and river valleys — section-walk it or take a fortnight end to end.'],
  ['Coast Track (Royal NP)','Royal National Park, NSW',['nsw'],'Moderate',26,'2 days',-34.13,151.07,'Sydney\'s classic overnighter along clifftops, heath and surf beaches from Bundeena to Otford — Wedding Cake Rock, Figure Eight Pools and whale-season views.'],
  ['Thorsborne Trail','Hinchinbrook Island, QLD',['qld'],'Challenging',32,'3-4 days',-18.4,146.25,'A capped-numbers wilderness walk down the east coast of Hinchinbrook Island — rainforest, mangroves, creek crossings and beach camps beneath Mt Bowen.'],
  ['Main Range Walk','Kosciuszko, NSW',['nsw'],'Challenging',22,'1 day',-36.43,148.27,'A high-alpine loop over Australia\'s roof past Blue Lake, Carruthers Peak and Mt Kosciuszko — glacial lakes and wildflowers in summer, serious in any other season.'],
  ['Mount Kosciuszko Summit Walk','Kosciuszko, NSW',['nsw'],'Moderate',13,'4-5 hrs',-36.46,148.26,'The walk to the mainland\'s highest point from Thredbo\'s chairlift — a raised-steel path across the alpine herbfields to the 2,228 m summit.'],
  ['Kings Canyon Rim Walk','Watarrka, NT',['nt'],'Moderate',6,'3-4 hrs',-24.25,131.57,'A loop around the rim of a sheer sandstone canyon to the "Garden of Eden" waterhole and the beehive domes of the Lost City — best at dawn before the heat.'],
  ['Uluru Base Walk','Uluṟu-Kata Tjuṯa, NT',['nt'],'Easy',10,'3-4 hrs',-25.34,131.04,'A flat loop around the base of Uluru past waterholes, caves and rock art, with interpretive signs sharing Anangu stories. Walk it early and respect the no-photo areas.'],
  ['Valley of the Winds','Kata Tjuṯa, NT',['nt'],'Moderate',7.4,'3 hrs',-25.3,130.73,'A loop between the great domes of Kata Tjuta to two lookouts — red conglomerate walls, spinifex and a real sense of scale. Closes by mid-morning on hot days.'],
  ['Mount Sonder','West MacDonnells, NT',['nt'],'Challenging',16,'6-8 hrs',-23.55,132.6,'The final Larapinta summit, usually walked as a sunrise return from Redbank Gorge — a long rocky climb rewarded by dawn over the ranges.'],
  ['Wineglass Bay & Hazards Beach Circuit','Freycinet, TAS',['tas'],'Moderate',11,'4-5 hrs',-42.15,148.3,'The day-walk version of Freycinet — the lookout, the famous beach, and a return over the isthmus past Hazards Beach.'],
  ['Cradle Mountain — Dove Lake Circuit','Cradle Mountain, TAS',['tas'],'Easy',6,'2-3 hrs',-41.66,145.95,'A boardwalked loop of Dove Lake beneath Cradle Mountain — the most photographed short walk in Tasmania, doable by most in a couple of hours.'],
  ['Gold Coast Hinterland Great Walk','Lamington & Springbrook, QLD',['qld'],'Moderate',54,'3 days',-28.23,153.13,'Through the Gondwana rainforests of Lamington and Springbrook — waterfalls, glow-worms and ancient Antarctic beech high above the Gold Coast.'],
  ['Sunshine Coast Hinterland Great Walk','Blackall Range, QLD',['qld'],'Moderate',58,'4 days',-26.7,152.85,'Linking Kondalilla and Mapleton Falls through subtropical rainforest and eucalypt ridges with hinterland views to the coast.'],
  ['Scenic Rim Trail','Main Range, QLD',['qld'],'Challenging',31,'4 days',-28.05,152.4,'A guided clifftop traverse of the Great Dividing Range\'s Main Range — escarpment edges, big drop-offs and World Heritage rainforest.'],
  ['Wukalina / Bay of Fires Walk','Bay of Fires, TAS',['tas'],'Moderate',34,'4 days',-41.0,148.28,'An Aboriginal-owned and -guided walk on palawa country along the orange-lichen granite and white beaches of the Bay of Fires.'],
  ['Maria Island Walk','Maria Island, TAS',['tas'],'Easy',32,'3-4 days',-42.6,148.07,'A gentle island walk past convict ruins, painted cliffs and abundant wildlife — wombats, Cape Barren geese and quiet white beaches, no cars.'],
  ['Kangaroo Island Wilderness Trail','Kangaroo Island, SA',['sa'],'Moderate',66,'5 days',-36.0,136.7,'A coast-and-bush traverse of the island\'s rugged south-west through Flinders Chase — Remarkable Rocks, Admirals Arch and recovering post-fire landscapes.'],
  ['St Mary Peak (Wilpena Pound)','Flinders Ranges, SA',['sa'],'Challenging',21,'8-9 hrs',-31.5,138.58,'The high point of the Flinders\' great natural amphitheatre — a long climb to a summit with views across the pound and out to the salt lakes. Respect the cultural request to stop below the summit.'],
  ['Mount Remarkable (Alligator Gorge)','Southern Flinders, SA',['sa'],'Moderate',18,'6-7 hrs',-32.8,138.0,'Gorge-and-summit walking in Mount Remarkable NP — red quartzite narrows at Alligator Gorge and a climb to the range tops near Melrose.'],
  ['Deep Creek Coast','Fleurieu Peninsula, SA',['sa'],'Moderate',24,'2 days',-35.6,138.27,'Clifftop and gully walking on the Fleurieu where the Heysen Trail meets the sea — Kangaroo Island views, waterfalls and steep descents to remote beaches.'],
  ['Great Ocean Walk — Cape Otway',"Cape Otway, VIC",['vic'],'Moderate',16,'1 day',-38.86,143.51,'A day section of the Great Ocean Walk around Cape Otway and its lighthouse — tall-forest, shipwreck coast and koalas in the manna gums.'],
  ['Mount Feathertop via Razorback','Alpine NP, VIC',['vic'],'Challenging',22,'1-2 days',-36.9,147.13,'Victoria\'s second-highest peak by its classic ridgeline — the exposed Razorback from Mt Hotham, spectacular and serious in changeable alpine weather.'],
  ['The Pinnacle (Grampians)','Halls Gap, VIC',['vic'],'Moderate',9.6,'4-5 hrs',-37.15,142.52,'The Grampians\' signature lookout above Halls Gap via the Grand Canyon and Silent Street — ladders, rock slots and a railed clifftop perch.'],
  ['Wineglass... Mount Amos','Freycinet, TAS',['tas'],'Challenging',4,'3 hrs',-42.13,148.3,'A steep granite scramble up Mt Amos for the textbook aerial view over Wineglass Bay — slippery when wet and not for the wary of heights.'],
  ['Light to Light Walk','Ben Boyd (Beowa) NP, NSW',['nsw'],'Moderate',30,'2-3 days',-37.18,150.0,'A far-south-coast walk between Boyds Tower and Green Cape lighthouse — red tessellated cliffs, white beaches and whale-season headlands.'],
  ['Murramarang South Coast Walk','Batemans Bay, NSW',['nsw'],'Moderate',34,'3-4 days',-35.6,150.3,'A newer multi-day coastal walk through spotted-gum forest and beach after beach on the NSW far south coast — kangaroos on the sand at Pebbly Beach.'],
  ['Mount Warning... Wollumbin (closed)','Tweed, NSW',['nsw'],'Moderate',8.8,'4-5 hrs',-28.4,153.27,'Note: the summit track on Wollumbin is closed at the request of its Aboriginal custodians. The surrounding caldera offers many alternative rainforest walks.'],
  ['Bald Rock Summit','New England, NSW',['nsw'],'Moderate',5,'2-3 hrs',-28.85,152.0,'The largest granite monolith in Australia after Uluru — a slabby open-rock climb to a summit with views across the New England and Granite Belt.'],
  ['Mount Field — Tarn Shelf','Mount Field NP, TAS',['tas'],'Moderate',12,'5-6 hrs',-42.68,146.57,'A glacial-shelf circuit of alpine tarns and deciduous fagus (Tasmania\'s only native deciduous tree, golden in autumn) above Lake Dobson.'],
]

let ok = 0
for (const w of W) {
  const [name, area, states, difficulty, length_km, duration, lat, lng, blurb] = w
  const slug = slugify(name)
  const length_m = Math.round(length_km * 1000)
  try {
    await sql`
      INSERT INTO autravel.trails (state_code, slug, name, trail_type, length_m, distance_label, duration_label, difficulty, area, center_lat, center_lng, start_lat, start_lng, source, source_raw, tags, active)
      VALUES (${STATE}, ${slug}, ${name}, 'Walking route', ${length_m}, ${km(length_km)}, ${duration}, ${difficulty}, ${area}, ${lat}, ${lng}, ${lat}, ${lng}, 'curated', ${sql.json({ blurb, states })}, ${sql.json({ states, iconic: true })}, true)
      ON CONFLICT (state_code, slug) DO UPDATE SET
        name=EXCLUDED.name, distance_label=EXCLUDED.distance_label, duration_label=EXCLUDED.duration_label,
        difficulty=EXCLUDED.difficulty, area=EXCLUDED.area, length_m=EXCLUDED.length_m,
        center_lat=EXCLUDED.center_lat, center_lng=EXCLUDED.center_lng, start_lat=EXCLUDED.start_lat,
        start_lng=EXCLUDED.start_lng, source_raw=EXCLUDED.source_raw, updated_at=now()`
    ok++
  } catch (e) { console.warn('  FAIL', name, e.message) }
}
console.log(`seeded ${ok}/${W.length} iconic walks (state_code='${STATE}')`)
await sql.end()
